package com.example.oaplicativo.model

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

@Serializable
data class Customer(
    val id: String? = null,
    val name: String = "",
    @SerialName("registration_number")
    val registrationNumber: String = "",
    @SerialName("registration_digit")
    val registrationDigit: String = "",
    val email: String = "",
    val landline: String = "",
    @SerialName("cell_phone")
    val cellPhone: String = "",
    @SerialName("is_standard_measurement_box")
    val isStandardMeasurementBox: Boolean = false,
    @SerialName("is_standardized_seals")
    val isStandardizedSeals: Boolean = false,
    @SerialName("is_hd_accessible")
    val isHdAccessible: Boolean = false,
    @SerialName("is_vacationer")
    val isVacationer: Boolean = false,
    val latitude: Double? = null,
    val longitude: Double? = null,
    @SerialName("created_at")
    val createdAt: String? = null
)

