package com.example.oaplicativo.ui.components

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp

@Composable
fun BooleanOption(label: String, checked: Boolean, onCheckedChange: (Boolean) -> Unit) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 8.dp)
    ) {
        Text(text = label, style = MaterialTheme.typography.bodyMedium)
        Row(
            verticalAlignment = Alignment.CenterVertically,
            modifier = Modifier.padding(top = 4.dp)
        ) {
            Checkbox(
                checked = checked,
                onCheckedChange = { if (it) onCheckedChange(true) }
            )
            Text(text = "Sim", style = MaterialTheme.typography.bodySmall)

            Spacer(modifier = Modifier.width(24.dp))

            Checkbox(
                checked = !checked,
                onCheckedChange = { if (it) onCheckedChange(false) }
            )
            Text(text = "Não", style = MaterialTheme.typography.bodySmall)
        }
    }
}

package com.example.oaplicativo.ui.components

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp

@Composable
fun BooleanOption(label: String, checked: Boolean?, onCheckedChange: (Boolean?) -> Unit) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 8.dp)
    ) {
        Text(text = label, style = MaterialTheme.typography.bodyMedium)
        Row(
            verticalAlignment = Alignment.CenterVertically,
            modifier = Modifier.padding(top = 4.dp)
        ) {
            Checkbox(
                checked = checked == true,
                onCheckedChange = { if (it) onCheckedChange(true) else onCheckedChange(null) }
            )
            Text(text = "Sim", style = MaterialTheme.typography.bodySmall)

            Spacer(modifier = Modifier.width(24.dp))

            Checkbox(
                checked = checked == false,
                onCheckedChange = { if (it) onCheckedChange(false) else onCheckedChange(null) }
            )
            Text(text = "Não", style = MaterialTheme.typography.bodySmall)
        }
    }
}

package com.example.oaplicativo.ui.screens.customer_form

import android.Manifest
import android.content.pm.PackageManager
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.text.KeyboardOptions
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Delete
import androidx.compose.material.icons.filled.LocationOn
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.input.KeyboardType
import androidx.compose.ui.unit.dp
import androidx.core.content.ContextCompat
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.oaplicativo.model.Customer
import com.example.oaplicativo.ui.components.BooleanOption
import com.example.oaplicativo.util.LocationHelper
import kotlinx.coroutines.launch

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CustomerFormScreen(
    customerId: String? = null,
    onSaveSuccess: () -> Unit,
    onBack: () -> Unit,
    viewModel: CustomerFormViewModel = viewModel()
) {
    val customer = remember(customerId) { viewModel.getCustomer(customerId) }

    var nome by remember(customer) { mutableStateOf(customer?.name ?: "") }
    var matricula by remember(customer) { mutableStateOf(customer?.registrationNumber ?: "") }
    var digitoMatricula by remember(customer) { mutableStateOf(customer?.registrationDigit ?: "") }
    var email by remember(customer) { mutableStateOf(customer?.email ?: "") }
    var telefoneFixo by remember(customer) { mutableStateOf(customer?.landline ?: "") }
    var celular by remember(customer) { mutableStateOf(customer?.cellPhone ?: "") }
    var isCaixaPadrao by remember(customer) { mutableStateOf(customer?.isStandardMeasurementBox ?: false) }
    var isLacresPadronizados by remember(customer) { mutableStateOf(customer?.isStandardizedSeals ?: false) }
    var isHdAcessivel by remember(customer) { mutableStateOf(customer?.isHdAccessible ?: false) }
    var isVeranista by remember(customer) { mutableStateOf(customer?.isVacationer ?: false) }
    var latitude by remember(customer) { mutableStateOf(customer?.latitude) }
    var longitude by remember(customer) { mutableStateOf(customer?.longitude) }

    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val locationHelper = remember { LocationHelper(context) }

    val locationPermissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions()
    ) { permissions ->
        if (permissions[Manifest.permission.ACCESS_FINE_LOCATION] == true ||
            permissions[Manifest.permission.ACCESS_COARSE_LOCATION] == true
        ) {
            scope.launch {
                val loc = locationHelper.getCurrentLocation()
                latitude = loc?.latitude
                longitude = loc?.longitude
            }
        }
    }

    val emailRegex = """^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\.[a-z]{2,}$""".toRegex()
    val formState by viewModel.state.collectAsState()

    var showErrors by remember { mutableStateOf(value = false) }

    val isNomeValid by remember { derivedStateOf { nome.length in 3..100 } }
    val isEmailValid by remember { derivedStateOf { (email.length in 5..254) && emailRegex.matches(email.trim()) } }
    val isMatriculaValid by remember { derivedStateOf { matricula.isNotEmpty() } }

    var showDeleteDialog by remember { mutableStateOf(false) }

    LaunchedEffect(formState) {
        if (formState is CustomerFormState.Success) {
            onSaveSuccess()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(if (customer == null) "Cadastrar Cliente" else "Atualizar Cliente") },
                actions = {
                    if (customer != null) {
                        IconButton(onClick = { showDeleteDialog = true }) {
                            Icon(Icons.Default.Delete, contentDescription = "Excluir Cliente", tint = MaterialTheme.colorScheme.error)
                        }
                    }
                }
            )
        }
    ) { paddingValues ->
        if (showDeleteDialog) {
            AlertDialog(
                onDismissRequest = { showDeleteDialog = false },
                title = { Text("Excluir Cliente") },
                text = { Text("Tem certeza que deseja excluir este cliente? Esta ação não pode ser desfeita e é um direito garantido pela LGPD.") },
                confirmButton = {
                    TextButton(
                        onClick = {
                            customer?.id?.let { viewModel.deleteCustomer(it) }
                            showDeleteDialog = false
                        },
                        colors = ButtonDefaults.textButtonColors(contentColor = MaterialTheme.colorScheme.error)
                    ) {
                        Text("Excluir")
                    }
                },
                dismissButton = {
                    TextButton(onClick = { showDeleteDialog = false }) {
                        Text("Cancelar")
                    }
                }
            )
        }
        Column(
            modifier = Modifier
                .padding(paddingValues)
                .padding(16.dp)
                .verticalScroll(rememberScrollState())
        ) {
            OutlinedTextField(
                value = nome,
                onValueChange = { if (it.length <= 100) nome = it },
                label = { Text("Nome") },
                modifier = Modifier.fillMaxWidth(),
                isError = showErrors && !isNomeValid,
                supportingText = {
                    if (showErrors && !isNomeValid) {
                        Text("O nome deve ter entre 3 e 100 caracteres")
                    }
                }
            )
            Spacer(modifier = Modifier.height(8.dp))
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                OutlinedTextField(
                    value = matricula,
                    onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 30) matricula = it },
                    label = { Text("Matrícula") },
                    modifier = Modifier.weight(1f),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                    isError = showErrors && !isMatriculaValid
                )
                OutlinedTextField(
                    value = digitoMatricula,
                    onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 2) digitoMatricula = it },
                    label = { Text("Díg.") },
                    modifier = Modifier.width(80.dp),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                )
            }
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value = email,
                onValueChange = { if (it.length <= 254) email = it },
                label = { Text("E-mail") },
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Email),
                isError = showErrors && !isEmailValid,
                supportingText = {
                    if (showErrors && !isEmailValid) {
                        Text("E-mail inválido (mínimo 5 caracteres)")
                    }
                }
            )
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value = telefoneFixo,
                onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 13) telefoneFixo = it },
                label = { Text("Telefone Fixo") },
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
            )
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value = celular,
                onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 13) celular = it },
                label = { Text("Celular") },
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
            )
            Spacer(modifier = Modifier.height(16.dp))

            BooleanOption(label = "Caixa de medição é padrão?", checked = isCaixaPadrao) { isCaixaPadrao = it }
            BooleanOption(label = "Lacres padronizados?", checked = isLacresPadronizados) { isLacresPadronizados = it }
            BooleanOption(label = "HD acessível?", checked = isHdAcessivel) { isHdAcessivel = it }
            BooleanOption(label = "Veranista?", checked = isVeranista) { isVeranista = it }

            Spacer(modifier = Modifier.height(16.dp))

            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text("Localização GPS", style = MaterialTheme.typography.titleSmall)
                    Spacer(modifier = Modifier.height(8.dp))
                    if (latitude != null && longitude != null) {
                        Text("Lat: $latitude", style = MaterialTheme.typography.bodyMedium)
                        Text("Long: $longitude", style = MaterialTheme.typography.bodyMedium)
                    } else {
                        Text("Nenhuma localização capturada", style = MaterialTheme.typography.bodyMedium)
                    }
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = "A localização é coletada apenas para fins de registro da visita técnica conforme a LGPD.",
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                    Button(
                        onClick = {
                            val fineLoc = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_FINE_LOCATION)
                            val coarseLoc = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_COARSE_LOCATION)

                            if (fineLoc == PackageManager.PERMISSION_GRANTED || coarseLoc == PackageManager.PERMISSION_GRANTED) {
                                scope.launch {
                                    val loc = locationHelper.getCurrentLocation()
                                    latitude = loc?.latitude
                                    longitude = loc?.longitude
                                }
                            } else {
                                locationPermissionLauncher.launch(
                                    arrayOf(
                                        Manifest.permission.ACCESS_FINE_LOCATION,
                                        Manifest.permission.ACCESS_COARSE_LOCATION
                                    )
                                )
                            }
                        },
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Icon(Icons.Default.LocationOn, contentDescription = null)
                        Spacer(modifier = Modifier.width(8.dp))
                        Text("Capturar Localização")
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            if (formState is CustomerFormState.Error) {
                Text(
                    text = (formState as CustomerFormState.Error).message,
                    color = MaterialTheme.colorScheme.error,
                    modifier = Modifier.padding(bottom = 8.dp)
                )
            }

            Spacer(modifier = Modifier.height(24.dp))
            Button(
                onClick = {
                    if (isNomeValid && isEmailValid && isMatriculaValid) {
                        viewModel.saveCustomer(
                            Customer(
                                id = customer?.id,
                                name = nome.trim(),
                                registrationNumber = matricula.trim(),
                                registrationDigit = digitoMatricula.trim(),
                                email = email.trim().lowercase(),
                                landline = telefoneFixo.trim(),
                                cellPhone = celular.trim(),
                                isStandardMeasurementBox = isCaixaPadrao,
                                isStandardizedSeals = isLacresPadronizados,
                                isHdAccessible = isHdAcessivel,
                                isVacationer = isVeranista,
                                latitude = latitude,
                                longitude = longitude
                            )
                        )
                    } else {
                        showErrors = true
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                enabled = formState !is CustomerFormState.Loading
            ) {
                if (formState is CustomerFormState.Loading) {
                    CircularProgressIndicator(
                        modifier = Modifier.size(24.dp),
                        color = MaterialTheme.colorScheme.onPrimary,
                        strokeWidth = 2.dp
                    )
                } else {
                    Text("Salvar")
                }
            }
            TextButton(
                onClick = { onBack() },
                modifier = Modifier.fillMaxWidth(),
                enabled = formState !is CustomerFormState.Loading
            ) {
                Text("Voltar")
            }
        }
    }
}

package com.example.oaplicativo.ui.screens.customer_form

import android.Manifest
import android.content.pm.PackageManager
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.text.KeyboardOptions
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Delete
import androidx.compose.material.icons.filled.LocationOn
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.input.KeyboardType
import androidx.compose.ui.unit.dp
import androidx.core.content.ContextCompat
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.oaplicativo.model.Customer
import com.example.oaplicativo.ui.components.BooleanOption
import com.example.oaplicativo.util.LocationHelper
import kotlinx.coroutines.launch

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CustomerFormScreen(
    customerId: String? = null,
    onSaveSuccess: () -> Unit,
    onBack: () -> Unit,
    viewModel: CustomerFormViewModel = viewModel()
) {
    val customer = remember(customerId) { viewModel.getCustomer(customerId) }

    var nome by remember(customer) { mutableStateOf(customer?.name ?: "") }
    var matricula by remember(customer) { mutableStateOf(customer?.registrationNumber ?: "") }
    var digitoMatricula by remember(customer) { mutableStateOf(customer?.registrationDigit ?: "") }
    var email by remember(customer) { mutableStateOf(customer?.email ?: "") }
    var telefoneFixo by remember(customer) { mutableStateOf(customer?.landline ?: "") }
    var celular by remember(customer) { mutableStateOf(customer?.cellPhone ?: "") }
    var isCaixaPadrao by remember(customer) { mutableStateOf(customer?.isStandardMeasurementBox) }
    var isLacresPadronizados by remember(customer) { mutableStateOf(customer?.isStandardizedSeals) }
    var isHdAcessivel by remember(customer) { mutableStateOf(customer?.isHdAccessible) }
    var isVeranista by remember(customer) { mutableStateOf(customer?.isVacationer) }
    var latitude by remember(customer) { mutableStateOf(customer?.latitude) }
    var longitude by remember(customer) { mutableStateOf(customer?.longitude) }

    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val locationHelper = remember { LocationHelper(context) }

    val locationPermissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions()
    ) { permissions ->
        if (permissions[Manifest.permission.ACCESS_FINE_LOCATION] == true ||
            permissions[Manifest.permission.ACCESS_COARSE_LOCATION] == true
        ) {
            scope.launch {
                val loc = locationHelper.getCurrentLocation()
                latitude = loc?.latitude
                longitude = loc?.longitude
            }
        }
    }

    val formState by viewModel.state.collectAsState()

    val isMatriculaValid by remember { derivedStateOf { matricula.isNotEmpty() } }

    var showDeleteDialog by remember { mutableStateOf(false) }

    LaunchedEffect(formState) {
        if (formState is CustomerFormState.Success) {
            onSaveSuccess()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(if (customer == null) "Cadastrar Cliente" else "Atualizar Cliente") },
                actions = {
                    if (customer != null) {
                        IconButton(onClick = { showDeleteDialog = true }) {
                            Icon(Icons.Default.Delete, contentDescription = "Excluir Cliente", tint = MaterialTheme.colorScheme.error)
                        }
                    }
                }
            )
        }
    ) { paddingValues ->
        if (showDeleteDialog) {
            AlertDialog(
                onDismissRequest = { showDeleteDialog = false },
                title = { Text("Excluir Cliente") },
                text = { Text("Tem certeza que deseja excluir este cliente? Esta ação não pode ser desfeita e é um direito garantido pela LGPD.") },
                confirmButton = {
                    TextButton(
                        onClick = {
                            customer?.id?.let { viewModel.deleteCustomer(it) }
                            showDeleteDialog = false
                        },
                        colors = ButtonDefaults.textButtonColors(contentColor = MaterialTheme.colorScheme.error)
                    ) {
                        Text("Excluir")
                    }
                },
                dismissButton = {
                    TextButton(onClick = { showDeleteDialog = false }) {
                        Text("Cancelar")
                    }
                }
            )
        }
        Column(
            modifier = Modifier
                .padding(paddingValues)
                .padding(16.dp)
                .verticalScroll(rememberScrollState())
        ) {
            OutlinedTextField(
                value = nome,
                onValueChange = { if (it.length <= 100) nome = it },
                label = { Text("Nome (Opcional)") },
                modifier = Modifier.fillMaxWidth()
            )
            Spacer(modifier = Modifier.height(8.dp))
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                OutlinedTextField(
                    value = matricula,
                    onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 30) matricula = it },
                    label = { Text("Matrícula") },
                    modifier = Modifier.weight(1f),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                )
                OutlinedTextField(
                    value = digitoMatricula,
                    onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 2) digitoMatricula = it },
                    label = { Text("Díg.") },
                    modifier = Modifier.width(80.dp),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                )
            }
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value = email,
                onValueChange = { if (it.length <= 254) email = it },
                label = { Text("E-mail (Opcional)") },
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Email)
            )
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value = telefoneFixo,
                onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 13) telefoneFixo = it },
                label = { Text("Telefone Fixo (Opcional)") },
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
            )
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value = celular,
                onValueChange = { if (it.all { char -> char.isDigit() } && it.length <= 13) celular = it },
                label = { Text("Celular (Opcional)") },
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
            )
            Spacer(modifier = Modifier.height(16.dp))

            BooleanOption(label = "Caixa de medição é padrão?", checked = isCaixaPadrao) { isCaixaPadrao = it }
            BooleanOption(label = "Lacres padronizados?", checked = isLacresPadronizados) { isLacresPadronizados = it }
            BooleanOption(label = "HD acessível?", checked = isHdAcessivel) { isHdAcessivel = it }
            BooleanOption(label = "Veranista?", checked = isVeranista) { isVeranista = it }

            Spacer(modifier = Modifier.height(16.dp))

            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text("Localização GPS", style = MaterialTheme.typography.titleSmall)
                    Spacer(modifier = Modifier.height(8.dp))
                    if (latitude != null && longitude != null) {
                        Text("Lat: $latitude", style = MaterialTheme.typography.bodyMedium)
                        Text("Long: $longitude", style = MaterialTheme.typography.bodyMedium)
                    } else {
                        Text("Nenhuma localização capturada", style = MaterialTheme.typography.bodyMedium)
                    }
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = "A localização é coletada apenas para fins de registro da visita técnica conforme a LGPD.",
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                    Button(
                        onClick = {
                            val fineLoc = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_FINE_LOCATION)
                            val coarseLoc = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_COARSE_LOCATION)

                            if (fineLoc == PackageManager.PERMISSION_GRANTED || coarseLoc == PackageManager.PERMISSION_GRANTED) {
                                scope.launch {
                                    val loc = locationHelper.getCurrentLocation()
                                    latitude = loc?.latitude
                                    longitude = loc?.longitude
                                }
                            } else {
                                locationPermissionLauncher.launch(
                                    arrayOf(
                                        Manifest.permission.ACCESS_FINE_LOCATION,
                                        Manifest.permission.ACCESS_COARSE_LOCATION
                                    )
                                )
                            }
                        },
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Icon(Icons.Default.LocationOn, contentDescription = null)
                        Spacer(modifier = Modifier.width(8.dp))
                        Text("Capturar Localização")
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            if (formState is CustomerFormState.Error) {
                Text(
                    text = (formState as CustomerFormState.Error).message,
                    color = MaterialTheme.colorScheme.error,
                    modifier = Modifier.padding(bottom = 8.dp)
                )
            }

            Spacer(modifier = Modifier.height(24.dp))
            Button(
                onClick = {
                    if (isMatriculaValid) {
                        viewModel.saveCustomer(
                            Customer(
                                id = customer?.id,
                                name = nome.trim(),
                                registrationNumber = matricula.trim(),
                                registrationDigit = digitoMatricula.trim(),
                                email = email.trim().lowercase(),
                                landline = telefoneFixo.trim(),
                                cellPhone = celular.trim(),
                                isStandardMeasurementBox = isCaixaPadrao ?: false,
                                isStandardizedSeals = isLacresPadronizados ?: false,
                                isHdAccessible = isHdAcessivel ?: false,
                                isVacationer = isVeranista ?: false,
                                latitude = latitude,
                                longitude = longitude
                            )
                        )
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                enabled = formState !is CustomerFormState.Loading
            ) {
                if (formState is CustomerFormState.Loading) {
                    CircularProgressIndicator(
                        modifier = Modifier.size(24.dp),
                        color = MaterialTheme.colorScheme.onPrimary,
                        strokeWidth = 2.dp
                    )
                } else {
                    Text("Salvar")
                }
            }
            TextButton(
                onClick = { onBack() },
                modifier = Modifier.fillMaxWidth(),
                enabled = formState !is CustomerFormState.Loading
            ) {
                Text("Voltar")
            }
        }
    }
}

package com.example.oaplicativo.ui.theme

import android.app.Activity
import android.os.Build
import androidx.compose.foundation.isSystemInDarkTheme
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.darkColorScheme
import androidx.compose.material3.dynamicDarkColorScheme
import androidx.compose.material3.dynamicLightColorScheme
import androidx.compose.material3.lightColorScheme
import androidx.compose.runtime.Composable
import androidx.compose.ui.platform.LocalContext

private val DarkColorScheme = darkColorScheme(
    primary = Purple80,
    secondary = PurpleGrey80,
    tertiary = Pink80
)

private val LightColorScheme = lightColorScheme(
    primary = Purple40,
    secondary = PurpleGrey40,
    tertiary = Pink40

    /* Other default colors to override
    background = Color(0xFFFFFBFE),
    surface = Color(0xFFFFFBFE),
    onPrimary = Color.White,
    onSecondary = Color.White,
    onTertiary = Color.White,
    onBackground = Color(0xFF1C1B1F),
    onSurface = Color(0xFF1C1B1F),
    */
)

@Composable
fun OAplicativoTheme(
    darkTheme: Boolean = isSystemInDarkTheme(),
    // Dynamic color is available on Android 12+
    dynamicColor: Boolean = true,
    content: @Composable () -> Unit
) {
    val colorScheme = when {
        dynamicColor && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S -> {
            val context = LocalContext.current
            if (darkTheme) dynamicDarkColorScheme(context) else dynamicLightColorScheme(context)
        }

        darkTheme -> DarkColorScheme
        else -> LightColorScheme
    }

    MaterialTheme(
        colorScheme = colorScheme,
        typography = Typography,
        content = content
    )
}

package com.example.oaplicativo.ui.theme

import android.app.Activity
